import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

function PostPage() {
  const [post, setPost] = useState(null);
  const [comments, setComments] = useState([]);
  const [commentBody, setCommentBody] = useState('');
  const [error, setError] = useState('');
  const { id } = useParams();
  const { user } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    fetchPost();
    fetchComments();
  }, [id]);

  const fetchPost = async () => {
    try {
      const { data } = await API.get(`/posts/${id}`);
      setPost(data);
    } catch (err) {
      setError('Post not found');
    }
  };

  const fetchComments = async () => {
    try {
      const { data } = await API.get(`/comments/${id}`);
      setComments(data);
    } catch (err) {
      console.error('Failed to fetch comments');
    }
  };

  const handleAddComment = async (e) => {
    e.preventDefault();
    if (!user) {
      navigate('/login');
      return;
    }
    try {
      const { data } = await API.post(`/comments/${id}`, { body: commentBody });
      setComments([...comments, data]);
      setCommentBody('');
    } catch (err) {
      setError('Failed to add comment');
    }
  };

  const handleDeleteComment = async (commentId) => {
    try {
      await API.delete(`/comments/${commentId}`);
      setComments(comments.filter(c => c._id !== commentId));
    } catch (err) {
      setError('Failed to delete comment');
    }
  };

  const handleDeletePost = async () => {
    if (window.confirm('Are you sure you want to delete this post?')) {
      try {
        await API.delete(`/posts/${id}`);
        navigate('/home');
      } catch (err) {
        setError('Failed to delete post');
      }
    }
  };

  if (error) return <div className="container error-msg">{error}</div>;
  if (!post) return <div className="container">Loading...</div>;

  const imageUrl = post.image ? `http://localhost:5000/uploads/${post.image}` : null;
  const canEdit = user && (user._id === post.author?._id || user.role === 'admin');
  const canDelete = user && (user._id === post.author?._id || user.role === 'admin');

  return (
    <div className="post-page container">
      {imageUrl && <img src={imageUrl} alt={post.title} className="post-cover" />}
      <h1>{post.title}</h1>
      <div className="post-meta">
        By {post.author?.name} on {new Date(post.createdAt).toLocaleDateString()}
      </div>
      <div className="post-body">{post.body}</div>

      {canEdit && (
        <button onClick={() => navigate(`/edit-post/${id}`)}>Edit Post</button>
      )}
      {canDelete && (
        <button onClick={handleDeletePost} className="delete-btn">Delete Post</button>
      )}

      <div className="comments-section">
        <h3>Comments ({comments.length})</h3>
        
        {user && (
          <form onSubmit={handleAddComment}>
            <textarea
              value={commentBody}
              onChange={(e) => setCommentBody(e.target.value)}
              placeholder="Write a comment..."
              rows="3"
              required
            />
            <button type="submit">Post Comment</button>
          </form>
        )}

        {comments.map(comment => (
          <div key={comment._id} className="comment">
            <strong>{comment.author?.name}</strong>
            <p>{comment.body}</p>
            {(user && (user._id === comment.author?._id || user.role === 'admin')) && (
              <button onClick={() => handleDeleteComment(comment._id)}>Delete</button>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

export default PostPage;
